Source code in <code>guard_core/handlers/behavior_handler.py</code> <pre><code>def get_recent_event_count(self, ip: str, window_seconds: int) -&gt; int:
    if not ip:
        return 0
    cutoff = time.time() - window_seconds
    count = 0
    for endpoint_bucket in self.usage_counts.values():
        for ts in endpoint_bucket.get(ip, []):
            if ts &gt;= cutoff:
                count += 1
    return count
